// MARK: - ASCIIArtRecordTests

struct ASCIIArtRecordTests {

    // MARK: Happy Path

    @Test func initStoresAllProperties() {
        let record = ASCIIArtRecord(
            id: "arrows/simple-right",
            title: "Simple Right Arrow",
            tags: ["arrow", "right"],
            category: "Arrows",
            filename: "Arrows/simple_right.txt"
        )
        #expect(record.id == "arrows/simple-right")
        #expect(record.title == "Simple Right Arrow")
        #expect(record.tags == ["arrow", "right"])
        #expect(record.category == "Arrows")
        #expect(record.filename == "Arrows/simple_right.txt")
    }

    @Test func codableRoundTrip() throws {
        let record = ASCIIArtRecord(id: "misc/dot", title: "Dot", tags: ["small"], category: "Misc", filename: "Misc/dot.txt")
        let data = try JSONEncoder().encode(record)
        let decoded = try JSONDecoder().decode(ASCIIArtRecord.self, from: data)
        #expect(decoded.id == "misc/dot")
        #expect(decoded.tags == ["small"])
    }

    // MARK: Edge Cases

    @Test func emptyTagsIsValid() {
        let record = ASCIIArtRecord(id: "x", title: "X", tags: [], category: "Cat", filename: "x.txt")
        #expect(record.tags.isEmpty)
    }

    @Test func hashableEqualForIdenticalValues() {
        let a = ASCIIArtRecord(id: "x", title: "T", tags: [], category: "C", filename: "f.txt")
        let b = ASCIIArtRecord(id: "x", title: "T", tags: [], category: "C", filename: "f.txt")
        #expect(a == b)
        #expect(a.hashValue == b.hashValue)
    }

    @Test func hashableDistinctForDifferentIDs() {
        let a = ASCIIArtRecord(id: "x", title: "T", tags: [], category: "C", filename: "f.txt")
        let b = ASCIIArtRecord(id: "y", title: "T", tags: [], category: "C", filename: "f.txt")
        #expect(a != b)
    }
}

