// MARK: - PreviewImageResolverTests

struct PreviewImageResolverTests {

    // MARK: Path Safety — all return .notFound without touching disk

    @Test func httpURLReturnsNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.resolve(reference: "http://example.com/img.png", relativeTo: .temporaryDirectory)
        #expect(result.isNotFound)
    }

    @Test func httpsURLReturnsNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.resolve(reference: "https://example.com/img.png", relativeTo: .temporaryDirectory)
        #expect(result.isNotFound)
    }

    @Test func dataURIReturnsNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.resolve(reference: "data:image/png;base64,abc", relativeTo: .temporaryDirectory)
        #expect(result.isNotFound)
    }

    @Test func absolutePathReturnsNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.resolve(reference: "/tmp/image.png", relativeTo: .temporaryDirectory)
        #expect(result.isNotFound)
    }

    @Test func dotDotEscapeReturnsNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.resolve(reference: "../etc/passwd", relativeTo: .temporaryDirectory)
        #expect(result.isNotFound)
    }

    @Test func embeddedDotDotReturnsNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.resolve(reference: "imgs/../../../etc/shadow", relativeTo: .temporaryDirectory)
        #expect(result.isNotFound)
    }

    @Test func nonExistentRelativeFileReturnsNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.resolve(reference: "no_such_file_sputnik.png", relativeTo: .temporaryDirectory)
        #expect(result.isNotFound)
    }

    // MARK: Happy Path

    @Test func validPNGFileReturnsImage() async throws {
        let resolver = PreviewImageResolver()
        let dir = URL.temporaryDirectory
        let imageURL = dir.appendingPathComponent("sputnik_test_img.png")

        let bitmapRep = NSBitmapImageRep(
            bitmapDataPlanes: nil,
            pixelsWide: 2,
            pixelsHigh: 2,
            bitsPerSample: 8,
            samplesPerPixel: 4,
            hasAlpha: true,
            isPlanar: false,
            colorSpaceName: .deviceRGB,
            bytesPerRow: 0,
            bitsPerPixel: 0
        )
        let pngData = try #require(bitmapRep?.representation(using: .png, properties: [:]))
        try pngData.write(to: imageURL)
        defer { try? FileManager.default.removeItem(at: imageURL) }

        let result = await resolver.resolve(reference: "sputnik_test_img.png", relativeTo: dir)
        #expect(result.isImage)
    }

    // MARK: Convenience Methods

    @Test func nsImageReturnsNilForNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.nsImage(reference: "nonexistent.png", relativeTo: .temporaryDirectory)
        #expect(result == nil)
    }

    @Test func dataReturnsNilForNotFound() async {
        let resolver = PreviewImageResolver()
        let result = await resolver.data(reference: "nonexistent.png", relativeTo: .temporaryDirectory)
        #expect(result == nil)
    }
}

// MARK: - ResolvedImage helpers

extension PreviewImageResolver.ResolvedImage {
    var isNotFound: Bool {
        if case .notFound = self { return true }
        return false
    }
    var isImage: Bool {
        if case .image = self { return true }
        return false
    }
}

