            title: "Subject and Predicate",
            searchTerms: ["sentence subject", "predicate"],
            kind: .grammar
        )
        #expect(!links.isEmpty)
        #expect(links[0].url.scheme == "https")
        #expect(links[0].url.host == "www.google.com")
        #expect(links[0].url.path == "/search")
